#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef float fp;

__kernel void extract_kernel(long d_Ne, fp *d_I) {
    int ei = get_global_id(0);
    if (ei < d_Ne) {
        d_I[ei] = exp(d_I[ei]);
    }
}

__kernel void prepare_kernel(long d_Ne, fp *d_I, fp *d_sums, fp *d_sums2) {
    int ei = get_global_id(0);
    if (ei < d_Ne) {
        d_sums[ei] = d_I[ei];
        d_sums2[ei] = d_I[ei] * d_I[ei];
    }
}

__kernel void reduce_kernel(long d_Ne, long no, int mul, fp *d_sums, fp *d_sums2, int blocks_work_size) {
    int ei = get_global_id(0);
    int tx = get_local_id(0);
    int local_size = get_local_size(0);

    int nf = local_size - ((blocks_work_size * local_size) - no);
    int df = 0;

    fp psum = 0.0f;
    fp psum2 = 0.0f;

    if (ei < no) {
        psum = d_sums[ei * mul];
        psum2 = d_sums2[ei * mul];
    }

    int bx = get_group_id(0);
    int grid_dim = get_num_groups(0);

    if (nf == local_size) {
        for (int i = 2; i <= local_size; i = i * 2) {
            if ((tx + 1) % i == 0) {
                psum += d_sums[(bx * local_size + tx - i/2) * mul]; 
                psum2 += d_sums2[(bx * local_size + tx - i/2) * mul];
            }
            barrier(CLK_LOCAL_MEM_FENCE);
        }
        if (tx == (local_size - 1)) {
            d_sums[bx * mul * local_size] = psum;
            d_sums2[bx * mul * local_size] = psum2;
        }
    } else {
        if (bx != (grid_dim - 1)) {
            for (int i = 2; i <= local_size; i = i * 2) {
                if ((tx + 1) % i == 0) {
                    psum += d_sums[(bx * local_size + tx - i/2) * mul];
                    psum2 += d_sums2[(bx * local_size + tx - i/2) * mul];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }
            if (tx == (local_size - 1)) {
                d_sums[bx * mul * local_size] = psum;
                d_sums2[bx * mul * local_size] = psum2;
            }
        } else {
            for (int i = 2; i <= local_size; i = i * 2) {
                if (nf >= i) {
                    df = i;
                }
            }

            for (int i = 2; i <= df; i = i * 2) {
                if ((tx + 1) % i == 0 && tx < df) {
                    psum += d_sums[(bx * local_size + tx - i/2) * mul];
                    psum2 += d_sums2[(bx * local_size + tx - i/2) * mul];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (df - 1)) {
                for (int i = (bx * local_size) + df; i < (bx * local_size) + nf; i++) {
                    psum += d_sums[i];
                    psum2 += d_sums2[i];
                }
                d_sums[bx * mul * local_size] = psum;
                d_sums2[bx * mul * local_size] = psum2;
            }
        }
    }
}

__kernel void srad_kernel(fp lambda, int Nr, int Nc, long Ne, 
                          int *d_iN, int *d_iS, int *d_jE, int *d_jW,
                          fp *d_dN, fp *d_dS, fp *d_dW, fp *d_dE,
                          fp q0sqr, fp *d_c, fp *d_I) {
    int i = get_global_id(0) / Nc;
    int j = get_global_id(0) % Nc;
    int k = get_global_id(0);

    if (k < Ne) {
        fp Jc = d_I[k];

        d_dN[k] = d_I[d_iN[i] * Nc + j] - Jc;
        d_dS[k] = d_I[d_iS[i] * Nc + j] - Jc;
        d_dW[k] = d_I[i * Nc + d_jW[j]] - Jc;
        d_dE[k] = d_I[i * Nc + d_jE[j]] - Jc;

        fp G2 = (d_dN[k]*d_dN[k] + d_dS[k]*d_dS[k] + d_dW[k]*d_dW[k] + d_dE[k]*d_dE[k]) / (Jc*Jc);
        fp L = (d_dN[k] + d_dS[k] + d_dW[k] + d_dE[k]) / Jc;

        fp num = (0.5f * G2) - ((1.0f/16.0f) * (L*L));
        fp den = 1.0f + (0.25f * L);
        fp qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
        d_c[k] = 1.0f / (1.0f + den);

        if (d_c[k] < 0.0f) d_c[k] = 0.0f;
        else if (d_c[k] > 1.0f) d_c[k] = 1.0f;
    }
}

__kernel void srad2_kernel(fp lambda, int Nr, int Nc, long Ne,
                           int *d_iN, int *d_iS, int *d_jE, int *d_jW,
                           fp *d_dN, fp *d_dS, fp *d_dW, fp *d_dE,
                           fp *d_c, fp *d_I) {
    int i = get_global_id(0) / Nc;
    int j = get_global_id(0) % Nc;
    int k = get_global_id(0);

    if (k < Ne) {
        fp cN = d_c[k];
        fp cS = d_c[d_iS[i] * Nc + j];
        fp cW = d_c[k];
        fp cE = d_c[i * Nc + d_jE[j]];

        fp D = cN * d_dN[k] + cS * d_dS[k] + cW * d_dW[k] + cE * d_dE[k];

        d_I[k] = d_I[k] + 0.25f * lambda * D;
    }
}

__kernel void compress_kernel(long d_Ne, fp *d_I) {
    int ei = get_global_id(0);
    if (ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * 255.0f;
    }
}
